 6	const normalizeCategory = (value: string) => value.toLowerCase().replaceAll('-', ' ');
 7	
 8	const getRestaurantResponse = (url: URL) => {
 9	  const id = url.searchParams.get('id');
10	
11	  if (id === '404') {
12	    return HttpResponse.json({ message: 'Restaurant not found' }, { status: 404 });
13	  }
14	
15	  if (id === '500') {
16	    return HttpResponse.json({ message: 'Internal server error' }, { status: 500 });
17	  }
18	
19	  if (id) {
20	    const restaurant = restaurantsCompleteData.find((item) => item.id === id);
21	
22	    if (!restaurant) {
23	      return HttpResponse.json({ message: 'Restaurant not found' }, { status: 404 });
24	    }
25	
26	    return HttpResponse.json(restaurant);
27	  }
28	
29	  const category = url.searchParams.get('category');
30	
31	  if (category) {
32	    const normalizedCategory = normalizeCategory(category);
33	    const restaurants = restaurantsCompleteData.filter((restaurant) =>
34	      restaurant.categories?.some((item) => normalizeCategory(item) === normalizedCategory)
35	    );
36	
37	    return HttpResponse.json(restaurants);
38	  }
39	
40	  return HttpResponse.json(restaurantsCompleteData);
41	};
